# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ElasticsearchException
import os
import time
from functools import lru_cache

app = Flask(__name__)

ES_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ES_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")
ES_TIMEOUT = float(os.getenv("ELASTICSEARCH_TIMEOUT", "2.0"))
ES_MAX_RETRIES = int(os.getenv("ELASTICSEARCH_MAX_RETRIES", "3"))
ES_RETRY_ON_TIMEOUT = os.getenv("ELASTICSEARCH_RETRY_ON_TIMEOUT", "true").lower() == "true"

es = Elasticsearch(
    ES_URL,
    request_timeout=ES_TIMEOUT,
    max_retries=ES_MAX_RETRIES,
    retry_on_timeout=ES_RETRY_ON_TIMEOUT,
    http_compress=True,
)

@lru_cache(maxsize=1024)
def _normalize_query(q):
    return " ".join(q.strip().lower().split())

def _build_search_body(query, size=20):
    return {
        "size": size,
        "track_total_hits": False,
        "_source": ["id", "name", "price", "image_url", "category", "brand", "in_stock"],
        "query": {
            "bool": {
                "should": [
                    {
                        "multi_match": {
                            "query": query,
                            "fields": ["name^4", "brand^2", "category^2", "description"],
                            "type": "best_fields",
                            "operator": "and",
                            "fuzziness": "AUTO",
                        }
                    },
                    {
                        "match_phrase_prefix": {
                            "name": {
                                "query": query,
                                "boost": 3,
                            }
                        }
                    }
                ],
                "minimum_should_match": 1
            }
        },
        "sort": [
            {"_score": "desc"},
            {"popularity": "desc"},
            {"updated_at": "desc"}
        ]
    }

@app.route("/api/search", methods=["GET"])
def search_products():
    q = request.args.get("q", "", type=str)
    if not q or not q.strip():
        return jsonify({"error": "Missing required query parameter: q"}), 400

    query = _normalize_query(q)
    size = request.args.get("size", default=20, type=int)
    size = max(1, min(size, 100))

    body = _build_search_body(query, size=size)

    start = time.time()
    try:
        resp = es.search(index=ES_INDEX, body=body)
    except ElasticsearchException:
        return jsonify({"error": "Search service unavailable"}), 503
    except Exception:
        return jsonify({"error": "Internal server error"}), 500

    hits = resp.get("hits", {}).get("hits", [])
    results = []
    for hit in hits:
        source = hit.get("_source", {})
        results.append({
            "id": source.get("id", hit.get("_id")),
            "name": source.get("name"),
            "price": source.get("price"),
            "image_url": source.get("image_url"),
            "category": source.get("category"),
            "brand": source.get("brand"),
            "in_stock": source.get("in_stock"),
            "score": hit.get("_score"),
        })

    elapsed_ms = round((time.time() - start) * 1000, 2)

    return jsonify({
        "query": q,
        "normalized_query": query,
        "count": len(results),
        "took_ms": elapsed_ms,
        "results": results,
    }), 200

@app.route("/health", methods=["GET"])
def health():
    try:
        es.ping(request_timeout=1)
        return jsonify({"status": "ok"}), 200
    except Exception:
        return jsonify({"status": "degraded"}), 503

if __name__ == "__main__":
    host = os.getenv("FLASK_HOST", "0.0.0.0")
    port = int(os.getenv("FLASK_PORT", "5000"))
    debug = os.getenv("FLASK_DEBUG", "false").lower() == "true"
    app.run(host=host, port=port, debug=debug)